let feParsed, beParsed;
try { feParsed = JSON.parse(frontendRaw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim()); } catch(e) { feParsed = { raw: frontendRaw }; }
try { beParsed = JSON.parse(backendRaw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim()); } catch(e) { beParsed = { raw: backendRaw }; }

return [{
  json: {
    ceo_plan: sharedSpecs.ceo_plan,
    ba_specs: sharedSpecs.ba_specs,
    architecture_specs: sharedSpecs.architecture_specs,
    frontend_code: feParsed,
    backend_code: beParsed
  }
}];

